import java.util.Arrays;

public class Solution {
    /**
     * Finds the maximum score of a valid subsequence.
     * A valid subsequence must satisfy:
     * 1. Index condition: For adjacent elements at indices i_t and i_{t+1}, i_{t+1} - i_t >= k.
     * 2. Alternating condition: The sequence of values must be strictly alternating (e.g., < > < ... or > < > ...).
     * The score is the sum of the values in the subsequence.
     *
     * @param nums The input array of integers.
     * @param k The minimum distance between adjacent indices.
     * @return The maximum possible score (as a long).
     */
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        if (n == 0) {
            return 0;
        }

        // dp_up[i]: Maximum score of a valid alternating subsequence ending at index i, 
        // where nums[i] is greater than the previous element (i.e., ... < nums[i]).
        // This means the sequence ends with an UP swing (or is of length 1).
        long[] dp_up = new long[n];

        // dp_down[i]: Maximum score of a valid alternating subsequence ending at index i, 
        // where nums[i] is smaller than the previous element (i.e., ... > nums[i]).
        // This means the sequence ends with a DOWN swing.
        long[] dp_down = new long[n];

        long maxScore = 0;

        for (int i = 0; i < n; i++) {
            // Base case: Subsequence of length 1 ending at i. Score is nums[i].
            dp_up[i] = nums[i];
            dp_down[i] = nums[i];

            // Iterate over all possible previous indices j
            // The condition is i - j >= k, or j <= i - k.
            for (int j = 0; j <= i - (int) k; j++) {
                // 1. Calculating dp_up[i]: Sequence ends with ... < nums[i].
                // The previous element nums[j] must be smaller than nums[i] (nums[j] < nums[i]).
                // The sequence ending at j must have ended with a DOWN swing (..., > nums[j]).
                if (nums[j] < nums[i]) {
                    dp_up[i] = Math.max(dp_up[i], dp_down[j] + nums[i]);
                }

                // 2. Calculating dp_down[i]: Sequence ends with ... > nums[i].
                // The previous element nums[j] must be greater than nums[i] (nums[j] > nums[i]).
                // The sequence ending at j must have ended with an UP swing (..., < nums[j]).
                if (nums[j] > nums[i]) {
                    dp_down[i] = Math.max(dp_down[i], dp_up[j] + nums[i]);
                }
            }

            // Update the overall maximum score found so far
            maxScore = Math.max(maxScore, dp_up[i]);
            maxScore = Math.max(maxScore, dp_down[i]);
        }

        return maxScore;
    }
}
