        int n = nums.length;
        if (n == 0) {
            return 0;
        }

        // dp_up[i]: Maximum score of a valid alternating subsequence ending at index i,
        // where nums[i] is GREATER than the previous element in the subsequence (i.e., ... < nums[i]).
        long[] dp_up = new long[n];

        // dp_down[i]: Maximum score of a valid alternating subsequence ending at index i,
        // where nums[i] is SMALLER than the previous element in the subsequence (i.e., ... > nums[i]).
        long[] dp_down = new long[n];

        long maxScore = 0;

        for (int i = 0; i < n; i++) {
            // Base case: A subsequence of length 1 always scores nums[i].
            dp_up[i] = nums[i];
            dp_down[i] = nums[i];

            // Check all previous indices j such that i - j >= k
            for (int j = 0; j <= i - k; j++) {
                // Case 1: Current sequence ends with ... < nums[i] (dp_up[i])
                // This means the previous element nums[j] must have been greater than nums[i] (i.e., dp_down[j] state).
                // We extend a sequence ending in 'down' at j with nums[i] which is larger.
                if (nums[i] > nums[j]) {
                    dp_up[i] = Math.max(dp_up[i], dp_down[j] + nums[i]);
