     */
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        if (n == 0) {
            return 0;
        }

        // DP state:
        // dp_up[i]: Maximum score of a valid subsequence ending at index i, where the sequence is increasing at the last step (i.e., a_m-1 < a_m = nums[i]).
        // dp_down[i]: Maximum score of a valid subsequence ending at index i, where the sequence is decreasing at the last step (i.e., a_m-1 > a_m = nums[i]).

        // Since the sequence can start with either increasing or decreasing trend relative to a hypothetical previous element, 
        // for a length 1 subsequence (just nums[i]), it's considered both "ending in up" and "ending in down" 
        // for the purpose of initialization, as it satisfies the alternating condition trivially.

        long[] dp_up = new long[n];
        long[] dp_down = new long[n];

        long maxScore = 0;

        for (int i = 0; i < n; i++) {
            // Initialize for length 1 subsequence
            dp_up[i] = nums[i];
            dp_down[i] = nums[i];

            // Iterate over all possible previous indices j
            // The constraint is i - j >= k, which means j <= i - k
            for (int j = 0; j <= i - k; j++) {

                // Transition to dp_up[i] (Current sequence ends with nums[j] < nums[i])
                // To end with an increase (nums[j] < nums[i]), the sequence ending at j must have ended with a decrease (dp_down[j]).
                if (nums[j] < nums[i]) {
